+        availability: TwoTierAvailability::HashOnly,
+        fast_status: ModelStatus::HashFallback,
+        quality_status: ModelStatus::DownloadBlocked {
+            model_name: "test".to_owned(),
+            reason: "offline".to_owned(),
+        },
+        cache_dir: "/tmp/cache".into(),
