+            id: "potion-128M".to_owned(),
+        },
+        quality_status: ModelStatus::Ready {
+            id: "MiniLM-L6-v2".to_owned(),
+        },
+        cache_dir: "/tmp/cache".into(),
+        offline: false,
+        suggestions: vec![],
